async function bindleftCommonSearchdropdown(ths, modulename, filtername) {
    var vm = ths;
    let url = `id=&moduleName=${modulename}&type=${filtername}&search=&refId=`;
    //  (string id, string moduleName, string type, string search, string refId
    if (filtername != 'License') {
        await DataService.GetDDLData(url).then(response => {
            var json = response.data.DATA;
            if (json != null) {
                if (filtername == "STATUS_NAMES") {
                    vm.leftSearchFields[3].listOptions = json.map((item) => {
                        const container = {};
                        container.name = item.name;
                        container.value = item.value.toString();
                        return container;
                    })
                } else if (filtername == "DEPARTMENT") {
                    vm.leftSearchFields[4].listOptions = json.map((item) => {
                        const container = {};
                        container.name = item.name;
                        container.value = item.value.toString();
                        return container;
                    })
                } else if (filtername == "LOCATION") {
                    vm.leftSearchFields[5].listOptions = json.map((item) => {
                        const container = {};
                        container.name = item.name;
                        container.value = item.value.toString();
                        return container;
                    })
                } else if (filtername == "USER_TYPES") {
                    vm.leftSearchFields[2].listOptions = json.map((item) => {
                        const container = {};
                        container.name = item.name;
                        container.value = item.value.toString();
                        return container;
                    })
                }
            }
        }).catch(err => {
            console.log(err);
        })
    }

    if (filtername == 'License') {
        await DataService.GetAllLicenses().then(response => {
            const jsonString = response.data.result[0]; // Extracting the JSON string from the array
            const jsonvalue = JSON.parse(jsonString);
            if (jsonvalue != null) {
                vm.leftSearchFields[6].listOptions = jsonvalue.map((item) => {
                    const container = {};
                    container.name = item.MODULE_NAME;
                    container.value = item.Module_Master_Id.toString();
                    return container;
                })
            }
        }).catch(err => {
            console.log(err);
        })
    }
}
